#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    std::vector<uint8_t> buffer;

    // Write data using buffer_adaptor (which provides both read and write)
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Check available space before writing (calculate from buffer size and write offset)
    std::size_t available = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();

    // Write the data
    adaptor.write(input_data.data(), input_data.size());

    // Read data back using the same adaptor
    // Check readable size
    std::size_t readable = adaptor.size();

    std::vector<uint8_t> result(readable);
    adaptor.read(result.data(), readable);

    return result;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    std::vector<uint8_t> buffer = buffer_data;
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Get read pointer
    auto* read_pos = read_adaptor.read_ptr();

    // Peek at data without advancing read cursor using copy()
    std::vector<uint8_t> peeked_data(peek_size);
    read_adaptor.copy(peeked_data.data(), peek_size);

    // Now actually read to consume the data
    std::vector<uint8_t> consumed_data(peek_size);
    read_adaptor.read(consumed_data.data(), peek_size);

    return peeked_data;
}

