#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        adaptor(sensor_id);

        // Write count of temperatures
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor(count);

        // Convert each temperature to little-endian and write using adaptor
        for (float temp : temperatures) {
            float le_temp = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor(le_temp);
        }

        // Convert pressure to little-endian and write using adaptor
        double le_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor(le_pressure);
    }

    void serialise(auto& adaptor) {
        adaptor(sensor_id);

        // Read count of temperatures
        uint32_t count;
        adaptor(count);

        temperatures.clear();
        temperatures.reserve(count);

        // Read each temperature and convert from little-endian to native in-place
        for (uint32_t i = 0; i < count; ++i) {
            float temp;
            adaptor & temp;
            hexi::endian::little_to_native_inplace(temp);
            temperatures.push_back(temp);
        }

        // Read pressure and convert from little-endian to native in-place
        adaptor & pressure;
        hexi::endian::little_to_native_inplace(pressure);
    }
};

